#include <iostream>
#include <fstream>
#include <string>
#include <stdexcept>

class DataProcessor {
public:
    double computeAverage(const std::string& filename) {
        std::ifstream file(filename);
        if (!file.is_open()) {
            throw std::runtime_error("Cannot open file");
        }
        int val;
        int sum = 0, count = 0;
        while (file >> val) {
            sum += val;
            count++;
        }
        if (!file.eof() && file.fail()) {
            throw std::invalid_argument("Non-integer metadata present");
        }
        file.close();
        if (count == 0) {
            throw std::domain_error("Empty file");
        }
        return (double)sum / count;
    }
};

