template <typename T>
class Stack {
private:
    std::vector<T> elements;
public:
    Stack() = default;
    ~Stack() = default;

    void push(const T& item) {
        elements.push_back(item);
    }

    void pop() {
        if (isEmpty()) {
            throw std::underflow_error("Stack underflow: Cannot pop from an empty stack.");
        }
        elements.pop_back();
    }

