void bubbleSort(int arr[], int n){
 for(int i=0;i<n-1;i++){
  for(int j=0;j<n-1-i;j++){
   if(arr[j] > arr[j+1]){
    int temp = arr[j];
    arr[j] = arr[j+1];
    arr[j+1] = temp;
   }
  }
 }
}

int linearSearch(int arr[], int n, int key){
 for(int i=0;i<n;i++){
  if(arr[i] == key)
   return i;
 }

 return -1;
}

int main(){
 int arr[10], key;

 for(int i=0;i<10;i++)
  cin >> arr[i];

 cin >> key;

 bubbleSort(arr,10);

 for(int i=0;i<10;i++)
  cout << arr[i] << " ";

 cout << endl;

 int pos = linearSearch(arr,10,key);

 if(pos != -1)
  cout << "Found at index " << pos;
 else
  cout << "Not Found";

 return 0;
}

