using namespace std;

bool isPerfect(int tomatoSoup){
 if(tomatoSoup<=1)
  return false;

 int soup=0;

 for(int i=1;i<tomatoSoup;i++){
  if(tomatoSoup%i==0)
   soup+=i;
 }

 return soup==tomatoSoup;
}

bool isCube(int tomatoSoup){
 for(int i=0;i*i*i<=tomatoSoup;i++){
  if(i*i*i==tomatoSoup)
   return true;
 }

 return false;
}

int countPerfect(int tomatoSoupArr[],int n){
 int tea=0;

 for(int i=0;i<n;i++){
  if(isPerfect(tomatoSoupArr[i]))
   tea++;
 }

 return tea;
}

int smallestDivisibleSeven(int tomatoSoupArr[],int n){
 int milk=999999;

 for(int i=0;i<n;i++){
  if(tomatoSoupArr[i]%7==0 && tomatoSoupArr[i]<milk)
   milk=tomatoSoupArr[i];
 }

 return milk;
}

int sumCubeNumbers(int tomatoSoupArr[],int n){
 int wow=0;

 for(int i=0;i<n;i++){
  if(isCube(tomatoSoupArr[i]))
   wow+=tomatoSoupArr[i];
 }

 return wow;
}

