 for(int i=0;i<6;i++)
  cin>>tomatoSoupArr[i];

 cout<<"Perfect Count = "<<countPerfect(tomatoSoupArr,6)<<endl;
 cout<<"Smallest Divisible by 7 = "<<smallestDivisibleSeven(tomatoSoupArr,6)<<endl;
