#include <iostream>
#include <fstream>
#include <string>

struct Employee {
    std::string name;
    int id;
    float salary;
};

void printEmployees(const Employee arr[], int size) {
    for (int i = 0; i < size; ++i) {
        std::cout << "ID: " << arr[i].id << " | Name: " << arr[i].name << " | Salary: $" << arr[i].salary << "\n";
    }
}

Employee findHighestSalary(const Employee arr[], int size) {
    Employee highest = arr[0];
    for (int i = 1; i < size; ++i) {
        if (arr[i].salary > highest.salary) {
            highest = arr[i];
        }
    }
    return highest;
}

float calculateAverageSalary(const Employee arr[], int size) {
    if (size == 0) return 0.0f;
    float total = 0.0f;
    for (int i = 0; i < size; ++i) {
        total += arr[i].salary;
    }
    return total / size;
}

int main() {
    std::ifstream inFile("employees.txt");
    if (!inFile) {
        std::cerr << "Error opening file!\n";
        return 1;
    }

    int capacity = 100;
    Employee* employees = new Employee[capacity];
    int count = 0;

    while (count < capacity && inFile >> employees[count].name >> employees[count].id >> employees[count].salary) {
        count++;
    }
    inFile.close();

    if (count == 0) {
        std::cout << "No records found.\n";
        delete[] employees;
        return 0;
    }

    std::cout << "--- All Employees ---\n";
    printEmployees(employees, count);

    std::cout << "\n--- Highest Paid Employee ---\n";
    Employee topEarner = findHighestSalary(employees, count);
    std::cout << "Name: " << topEarner.name << " (ID: " << topEarner.id << ") with Salary: $" << topEarner.salary << "\n";

    std::cout << "\nAverage Salary: $" << calculateAverageSalary(employees, count) << "\n";

    delete[] employees;
    return 0;
}

