struct Time {
    int hour;
    int minute;
    int second;
};

void setTime(Time &t) {
    std::cin >> t.hour >> t.minute >> t.second;
}

void printTime(const Time &t) {
    std::cout << std::setfill('0') 
              << std::setw(2) << t.hour << ":"
              << std::setw(2) << t.minute << ":"
              << std::setw(2) << t.second << "\n";
}

void increaseTime(Time &t, int sec) {
    int totalSeconds = t.hour * 3600 + t.minute * 60 + t.second + sec;
    if (totalSeconds < 0) totalSeconds = 0;

    t.hour = (totalSeconds / 3600) % 24;
    t.minute = (totalSeconds % 3600) / 60;
    t.second = totalSeconds % 60;
}

int main() {
    int n;
    if (!(std::cin >> n) || n <= 0) return 0;

    Time* appointments = new Time[n];

    for (int i = 0; i < n; ++i) {
        setTime(appointments[i]);
    }

    for (int i = 0; i < n; ++i) {
        printTime(appointments[i]);
    }

    delete[] appointments;
    return 0;
}

