#include <iostream>
#include <iomanip>

struct Time { int hour; int minute; int second; };

void setTime(Time &t) { std::cin >> t.hour >> t.minute >> t.second; }
void printTime(const Time &t) {
    std::cout << std::setfill('0') << std::setw(2) << t.hour << ":"
              << std::setw(2) << t.minute << ":" << std::setw(2) << t.second << "\n";
}

void increaseTime(Time &t, int sec) {
    t.second += sec;
    if (t.second >= 60) {
        t.second -= 60;
        t.minute++;
    }
    if (t.minute >= 60) {
        t.minute -= 60;
        t.hour++;
    }
    if (t.hour >= 24) {
        t.hour -= 24;
    }
}

int main() {
    int n; std::cin >> n;
    Time* appointments = new Time[n];
    for(int i = 0; i < n; i++) setTime(appointments[i]);
    for(int i = 0; i < n; i++) printTime(appointments[i]);
    delete[] appointments;
    return 0;
}

