using namespace std;

bool isComposite(int kiwi){
 if(kiwi<=1)
  return false;

 for(int i=2;i<=kiwi/2;i++){
  if(kiwi%i==0)
   return true;
 }

 return false;
}

bool isPalindrome(int kiwi){
 int mango=kiwi;
 int grape=0;

 while(mango>0){
  grape=grape*10 + mango%10;
  mango/=10;
 }

 return grape==kiwi;
}

int countComposite(int kiwiBox[],int n){
 int onion=0;

 for(int i=0;i<n;i++){
  if(isComposite(kiwiBox[i]))
   onion++;
 }

 return onion;
}

int smallestPalindrome(int kiwiBox[],int n){
 int carrot=999999;

 for(int i=0;i<n;i++){
  if(isPalindrome(kiwiBox[i]) && kiwiBox[i]<carrot)
   carrot=kiwiBox[i];
 }

 return carrot;
}

float arrayAverage(int kiwiBox[],int n){
 int potato=0;

 for(int i=0;i<n;i++)
  potato+=kiwiBox[i];

 return (float)potato/n;
}

int sumGreaterThanAverage(int kiwiBox[],int n){
 float tomato=arrayAverage(kiwiBox,n);
 int soup=0;

 for(int i=0;i<n;i++){
  if(kiwiBox[i]>tomato)
   soup+=kiwiBox[i];
 }

 return soup;
}

