class Rectangle {
private:
    double width;
    double height;

public:
    Rectangle(double w, double h) {
        width = (w <= 0.0) ? 1.0 : w;
        height = (h <= 0.0) ? 1.0 : h;
    }

    double getWidth() const { return width; }
    double getHeight() const { return height; }

    double getArea() const {
        return width * height;
    }

    double getPerimeter() const {
        return 2.0 * (width + height);
    }

    bool isSquare() const {
        return width == height;
    }
};

