#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <algorithm>

bool frequencyComparator(const std::pair<std::string, int>& a, const std::pair<std::string, int>& b) {
    if (a.second == b.second) {
        return a.first < b.first;
    }
    return a.second > b.second;
}

std::vector<std::pair<std::string, int>> sortWordsByFrequency(const std::vector<std::string>& words) {
    std::map<std::string, int> freqMap;
    for (const std::string& word : words) {
        freqMap[word]++;
    }

    std::vector<std::pair<std::string, int>> freqVec(freqMap.begin(), freqMap.end());
    std::sort(freqVec.begin(), freqVec.end(), frequencyComparator);

    return freqVec;
}

