#include <vector>
#include <string>
#include <map>
#include <algorithm>

std::vector<std::pair<std::string, int>> sortWordsByFrequency(const std::vector<std::string>& words) {
    std::map<std::string, int> freqMap;
    for (const std::string& word : words) {
        freqMap[word]++;
    }

    std::vector<std::pair<std::string, int>> freqVec(freqMap.begin(), freqMap.end());

    for (size_t i = 0; i < freqVec.size(); i++) {
        for (size_t j = i + 1; j < freqVec.size(); j++) {
            if (freqVec[i].second < freqVec[j].second || 
               (freqVec[i].second == freqVec[j].second && freqVec[i].first > freqVec[j].first)) {
                std::swap(freqVec[i], freqVec[j]);
            }
        }
    }
    return freqVec;
}

