#include <iostream>
#include <fstream>
#include <string>

struct Employee { std::string name; int id; float salary; };

void printEmployees(Employee arr[], int size) {
    for(int i = 0; i < size; i++) std::cout << arr[i].name << "\n";
}

Employee findHighestSalary(Employee arr[], int size) {
    Employee maxEmp = arr[0];
    for(int i = 1; i < size; i++) {
        if(arr[i].salary > maxEmp.salary) maxEmp = arr[i];
    }
    return maxEmp;
}

float calculateAverageSalary(Employee arr[], int size) {
    float sum = 0;
    for(int i = 0; i < size; i++) sum += arr[i].salary;
    return sum / size;
}

int main() {
    std::ifstream file("employees.txt");
    Employee* employees = new Employee[100];
    int count = 0;
    while(file >> employees[count].name >> employees[count].id >> employees[count].salary) count++;
    file.close();

    printEmployees(employees, count);
    delete[] employees;
    return 0;
}

